parameters.jsCode:
const root = $('Webhook Invoice').first().json;
const b = root.body || root;

const order_number = String(b.order_number || b.order_id || 'б/н');
const customer_type = String(b.customer_type || 'individual');
const amount = b.amount ? Number(b.amount).toLocaleString('ru-RU') : null;
const customer_name = String(b.customer_name || '');
const preferred_contact = String(b.preferred_contact || 'telegram');
const customer_phone = String(b.customer_phone || '');

const amountLine = amount ? `\n\uD83D\uDCB0 Сумма: ${amount} ₽` : '';
const nameLine = customer_name ? `\n\uD83D\uDC64 Клиент: ${customer_name}` : '';

let text;
if (customer_type === 'legal_entity') {
  const companyInn = $env.COMPANY_INN || 'уточните у менеджера';
  const companyBank = $env.COMPANY_BANK || 'уточните у менеджера';
  const companyAccount = $env.COMPANY_ACCOUNT || 'уточните у менеджера';
  const companyBik = $env.COMPANY_BIK || 'уточните у менеджера';
  text = `\uD83E\uDDFE *Счёт на оплату — Заказ ${order_number}*${nameLine}${amountLine}\n\n\uD83D\uDCCB *Реквизиты для оплаты:*\nИНН: ${companyInn}\nБанк: ${companyBank}\nРасчётный счёт: ${companyAccount}\nБИК: ${companyBik}\n\nВ назначении платежа укажите номер заказа: ${order_number}`;
} else {
  const sbpPhone = $env.COMPANY_SBP_PHONE || 'уточните у менеджера';
  text = `\uD83D\uDCB3 *Оплата по СБП — Заказ ${order_number}*${nameLine}${amountLine}\n\n\uD83D\uDCF2 *Реквизиты СБП:*\nТелефон: ${sbpPhone}\n\nПосле оплаты пришлите скриншот — мы подтвердим получение.`;
}

return [{ json: { text, preferred_contact, customer_phone } }];

const msgData = $('Build Message').first().json;
const tokenRows = $input.first().json;
const tokenRow = Array.isArray(tokenRows) ? tokenRows[0] : tokenRows;
const messengerId = tokenRow?.messenger_id || null;
const preferred_contact = msgData.preferred_contact;
return [{ json: {
  text: msgData.text,
  preferred_contact,
  telegram_chat_id: preferred_contact === 'telegram' && messengerId ? String(messengerId) : null,
  max_user_id: preferred_contact === 'max' && messengerId ? String(messengerId) : null
} }];

